mapper.select:
SELECT NVL(MAX(BID_PRICE), 0)
FROM BID
WHERE ITEM_NO = #{itemNo}

SELECT RN
FROM (
    SELECT BID_NO,
           ROW_NUMBER() OVER (ORDER BY BID_PRICE DESC, BID_TIME ASC) AS RN
    FROM BID
    WHERE ITEM_NO = #{itemNo}
)
WHERE BID_NO = #{bidNo}

SELECT COUNT(*)
FROM BID
WHERE ITEM_NO = #{itemNo}

mapper.update:
UPDATE ITEM
SET CURRENT_PRICE = #{currentPrice}
WHERE ITEM_NO = #{itemNo}

UPDATE BID
SET BID_STATUS = #{status}
WHERE BID_NO = #{bidNo}
	AND BID_STATUS IS NULL
